    else if (this.options.ecmaVersion >= 9) node.await = false
  }
  if (startsWithLet && isForOf) this.raise(init.start, "The left-hand side of a for-of loop may not start with 'let'.")
  this.toAssignable(init, false, refDestructuringErrors)
  this.checkLValPattern(init)
  return this.parseForIn(node, init)
} else {
  this.checkExpressionErrors(refDestructuringErrors, true)
}

for (;;) {
  let decl = this.startNode()
  this.parseVarId(decl, kind)
  if (this.eat(tt.eq)) {
    decl.init = this.parseMaybeAssign(isFor)
  } else if (!allowMissingInitializer && kind === "const" && !(this.type === tt._in || (this.options.ecmaVersion >= 6 && this.isContextual("of")))) {
    this.unexpected()
  } else if (!allowMissingInitializer && (kind === "using" || kind === "await using") && this.options.ecmaVersion >= 17 && this.type !== tt._in && !this.isContextual("of")) {
    this.raise(this.lastTokEnd, `Missing initializer in ${kind} declaration`)
  } else if (!allowMissingInitializer && decl.id.type !== "Identifier" && !(isFor && (this.type === tt._in || this.isContextual("of")))) {
    this.raise(this.lastTokEnd, "Complex binding patterns require an initialization value")
  } else {
    decl.init = null
  }
  node.declarations.push(this.finishNode(decl, "VariableDeclarator"))
  if (!this.eat(tt.comma)) break
}

if (suites.length) {
  // Run next suite.
  suites[0].run({ 'async': true });
}
else {
  var aMeanHz = getGeometricMean(score.a),
      bMeanHz = getGeometricMean(score.b),
      fastestMeanHz = Math.max(aMeanHz, bMeanHz),
      slowestMeanHz = Math.min(aMeanHz, bMeanHz),
      xFaster = fastestMeanHz / slowestMeanHz,
      percentFaster = formatNumber(Math.round((xFaster - 1) * 100)),
      message = 'is ' + percentFaster + '% ' + (xFaster == 1 ? '' : '(' + formatNumber(xFaster.toFixed(2)) + 'x) ') + 'faster than';

  // Report results.
  if (aMeanHz >= bMeanHz) {
    log('\n' + buildName + ' ' + message + ' ' + otherName + '.');
  } else {
    log('\n' + otherName + ' ' + message + ' ' + buildName + '.');
  }
}

for (var i = 0, p; p = stack.parent(i++); node = p) {
    if (is_arrow(p)) {
        return arrow && p.value === node;
    } else if (p instanceof AST_Binary) {
        if (p.left === node) continue;
    } else if (p.TYPE == "Call") {
        if (p.expression === node) continue;
    } else if (p instanceof AST_Conditional) {
        if (p.condition === node) continue;
    } else if (p instanceof AST_ExportDefault) {
        return export_default;
    } else if (p instanceof AST_PropAccess) {
        if (p.expression === node) continue;
    } else if (p instanceof AST_Sequence) {
        if (p.expressions[0] === node) continue;
    } else if (p instanceof AST_SimpleStatement) {
        return true;
    } else if (p instanceof AST_Template) {
        if (p.tag === node) continue;
    } else if (p instanceof AST_UnaryPostfix) {
        if (p.expression === node) continue;
    }
    return false;
}

for (let q = 0; q < count; q++) {
  const data = argsArray[iFirstPIIXO + (q << 2)][0].data;
  // Copy image by lines and extends pixels into padding.
  const rowSize = map[q].w << 2;
  let dataOffset = 0;
  let offset = (map[q].x + map[q].y * imgWidth) << 2;
  imgData.set(data.subarray(0, rowSize), offset - imgRowSize);
  for (let k = 0, kk = map[q].h; k < kk; k++) {
    imgData.set(data.subarray(dataOffset, dataOffset + rowSize), offset);
    dataOffset += rowSize;
    offset += imgRowSize;
  }
  imgData.set(data.subarray(dataOffset - rowSize, dataOffset), offset);
  while (offset >= 0) {
    data[offset - 4] = data[offset];
    data[offset - 3] = data[offset + 1];
    data[offset - 2] = data[offset + 2];
    data[offset - 1] = data[offset + 3];
    data[offset + rowSize] = data[offset + rowSize - 4];
    data[offset + rowSize + 1] = data[offset + rowSize - 3];
    data[offset + rowSize + 2] = data[offset + rowSize - 2];
    data[offset + rowSize + 3] = data[offset + rowSize - 1];
    offset -= imgRowSize;
  }
}

for (const figure of figures) {
  const ps = figure.coords;
  const cs = figure.colors;
  if (figure.type === MeshFigureType.TRIANGLES) {
    for (let i = 0, ii = ps.length; i < ii; i++) {
      addVertex(ps[i], cs[i]);
    }
  } else if (figure.type === MeshFigureType.LATTICE) {
    const vpr = figure.verticesPerRow;
    const rows = Math.floor(ps.length / vpr) - 1;
    const cols = vpr - 1;
    for (let i = 0; i < rows; i++) {
      let q = i * vpr;
      for (let j = 0; j < cols; j++, q++) {
        addVertex(ps[q], cs[q]);
        addVertex(ps[q + 1], cs[q + 1]);
        addVertex(ps[q + vpr], cs[q + vpr]);
        addVertex(ps[q + vpr + 1], cs[q + vpr + 1]);
        addVertex(ps[q + 1], cs[q + 1]);
        addVertex(ps[q + vpr], cs[q + vpr]);
      }
    }
  }
}

createModuleReference(
	module,
	{
		ids = undefined,
		call = false,
		directImport = false,
		deferredImport = false,
		asiSafe = false
	}
) {
	const info = /** @type {ModuleInfo} */ (this._modulesMap.get(module));
	const callFlag = call ? "_call" : "";
	const directImportFlag = directImport ? "_directImport" : "";
	const deferredImportFlag = deferredImport ? "_deferredImport" : "";
	const asiSafeFlag = asiSafe
		? "_asiSafe1"
		: asiSafe === false
			? "_asiSafe0"
			: "";
	const exportData = ids
		? Buffer.from(JSON.stringify(ids), "utf8").toString("hex")
		: "ns";
	// a "._" is appended to allow "delete ...", which would cause a SyntaxError in strict mode
	return `__WEBPACK_MODULE_REFERENCE__${info.index}_${exportData}${callFlag}${directImportFlag}${deferredImportFlag}${asiSafeFlag}__._`;
}

class BreakBefore extends XFAObject {
  constructor(attributes) {
    super(TEMPLATE_NS_ID, "breakBefore", /* hasChildren = */ true);
    this.id = attributes.id || "";
    this.leader = attributes.leader || "";
    this.startNew = getInteger({
      data: attributes.startNew,
      defaultValue: 0,
      validate: x => x === 1,
    });
    this.target = attributes.target || "";
    this.targetType = getStringOption(attributes.targetType, [
      "auto",
      "contentArea",
      "pageArea",
    ]);
    this.trailer = attributes.trailer || "";
    this.use = attributes.use || "";
    this.usehref = attributes.usehref || "";
    this.script = null;
  }

  [$toHTML](availableSpace) {
    this[$extra] = {};
    return HTMLResult.FAILURE;
  }
}

class Linear extends XFAObject {
  constructor(attributes) {
    super(TEMPLATE_NS_ID, "linear", /* hasChildren = */ true);
    this.id = attributes.id || "";
    this.type = getStringOption(attributes.type, [
      "toRight",
      "toBottom",
      "toLeft",
      "toTop",
    ]);
    this.use = attributes.use || "";
    this.usehref = attributes.usehref || "";
    this.color = null;
    this.extras = null;
  }

  [$toStyle](startColor) {
    startColor = startColor ? startColor[$toStyle]() : "#FFFFFF";
    const transf = this.type.replace(/([RBLT])/, " $1").toLowerCase();
    const endColor = this.color ? this.color[$toStyle]() : "#000000";
    return `linear-gradient(${transf}, ${startColor}, ${endColor})`;
  }
}

class Radial extends XFAObject {
  constructor(attributes) {
    super(TEMPLATE_NS_ID, "radial", /* hasChildren = */ true);
    this.id = attributes.id || "";
    this.type = getStringOption(attributes.type, ["toEdge", "toCenter"]);
    this.use = attributes.use || "";
    this.usehref = attributes.usehref || "";
    this.color = null;
    this.extras = null;
  }

  [$toStyle](startColor) {
    startColor = startColor ? startColor[$toStyle]() : "#FFFFFF";
    const endColor = this.color ? this.color[$toStyle]() : "#000000";
    const colors =
      this.type === "toEdge"
        ? `${startColor},${endColor}`
        : `${endColor},${startColor}`;
    return `radial-gradient(circle at center, ${colors})`;
  }
}

class Stipple extends XFAObject {
  constructor(attributes) {
    super(TEMPLATE_NS_ID, "stipple", /* hasChildren = */ true);
    this.id = attributes.id || "";
    this.rate = getInteger({
      data: attributes.rate,
      defaultValue: 50,
      validate: x => x >= 0 && x <= 100,
    });
    this.use = attributes.use || "";
    this.usehref = attributes.usehref || "";
    this.color = null;
    this.extras = null;
  }

  [$toStyle](bgColor) {
    const alpha = this.rate / 100;
    return Util.makeHexColor(
      Math.round(bgColor.value.r * (1 - alpha) + this.value.r * alpha),
      Math.round(bgColor.value.g * (1 - alpha) + this.value.g * alpha),
      Math.round(bgColor.value.b * (1 - alpha) + this.value.b * alpha)
    );
  }
}
